  1	import React from 'react';
  2	
  3	import { AnnotationsModal } from '@kubevirt-utils/components/AnnotationsModal/AnnotationsModal';
  4	import { LabelsModal } from '@kubevirt-utils/components/LabelsModal/LabelsModal';
  5	import Loading from '@kubevirt-utils/components/Loading/Loading';
  6	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
  7	import SearchItem from '@kubevirt-utils/components/SearchItem/SearchItem';
  8	import VirtualMachineDescriptionItem from '@kubevirt-utils/components/VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
  9	import { documentationURL } from '@kubevirt-utils/constants/documentation';
 10	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 11	import { getName } from '@kubevirt-utils/resources/shared';
 12	import { updateCustomizeInstanceType, vmSignal } from '@kubevirt-utils/store/customizeInstanceType';
 13	import {
 14	  DescriptionList,
 15	  Grid,
 16	  PageSection,
 17	  PageSectionVariants,
 18	  Title,
 19	} from '@patternfly/react-core';
 20	import MetadataTabAnnotations from '@virtualmachines/details/tabs/configuration/metadata/components/MetadataTabAnnotations/MetadataTabAnnotations';
 21	import MetadataTabLabels from '@virtualmachines/details/tabs/configuration/metadata/components/MetadataTabLabels/MetadataTabLabels';
 22	
 23	const CustomizeInstanceTypeMetadataTab = () => {
 24	  const { createModal } = useModal();
 25	  const { t } = useKubevirtTranslation();
 26	  const vm = vmSignal.value;
 27	
 28	  if (!vm) {
 29	    return <Loading />;
 30	  }
 31	
 32	  const updateMetadata = (data: { [key: string]: string }, type: string) =>
 33	    Promise.resolve(
 34	      updateCustomizeInstanceType([
 35	        {
 36	          data,
 37	          path: `metadata.${type}`,
 38	        },
 39	      ]),
 40	    );
 41	
 42	  return (
 43	    <PageSection variant={PageSectionVariants.light}>
 44	      <Title headingLevel="h2">
 45	        <SearchItem id="metadata">{t('Metadata')}</SearchItem>
 46	      </Title>
 47	      <Grid span={6}>
 48	        <DescriptionList className="pf-v6-c-description-list">
 49	          <VirtualMachineDescriptionItem
 50	            bodyContent={t(
 51	              'Map of string keys and values that can be used to organize and categorize (scope and select) objects. May match selectors of replication controllers and services. ',
 52	            )}
 53	            onEditClick={() =>
 54	              createModal(({ isOpen, onClose }) => (
 55	                <LabelsModal
 56	                  isOpen={isOpen}
 57	                  obj={vm}
 58	                  onClose={onClose}
 59	                  onLabelsSubmit={(labels) => updateMetadata(labels, 'labels')}
 60	                />
 61	              ))
 62	            }
 63	            breadcrumb="VirtualMachine.metadata.labels"
 64	            data-test-id={`${getName(vm)}-labels`}
 65	            descriptionData={<MetadataTabLabels labels={vm?.metadata?.labels} />}
 66	            descriptionHeader={<SearchItem id="labels">{t('Labels')}</SearchItem>}
 67	            editOnTitleJustify
 68	            isEdit
 69	            isPopover
 70	            moreInfoURL={documentationURL.LABELS}
 71	            showEditOnTitle
 72	          />
 73	          <VirtualMachineDescriptionItem
 74	            bodyContent={t(
 75	              'Annotations is an unstructured key value map stored with a resource that may be set by external tools to store and retrieve arbitrary metadata. They are not queryable and should be preserved when modifying objects. ',
 76	            )}
 77	            onEditClick={() =>
 78	              createModal(({ isOpen, onClose }) => (
 79	                <AnnotationsModal
 80	                  isOpen={isOpen}
 81	                  obj={vm}
 82	                  onClose={onClose}
 83	                  onSubmit={(annotations) => updateMetadata(annotations, 'annotations')}
 84	                />
 85	              ))
 86	            }
 87	            breadcrumb="VirtualMachine.metadata.annotations"
 88	            descriptionData={<MetadataTabAnnotations annotations={vm?.metadata?.annotations} />}
 89	            descriptionHeader={<SearchItem id="metadata">{t('Annotations')}</SearchItem>}
 90	            isEdit
 91	            isPopover
 92	            moreInfoURL={documentationURL.ANNOTATIONS}
 93	          />
 94	        </DescriptionList>
 95	      </Grid>
 96	    </PageSection>
 97	  );
 98	};
 99	
100	export default CustomizeInstanceTypeMetadataTab;

